curr_blk = 0

with open(binanlys_log_file) as blf:

    lines = blf.readlines()
    starts = [lines.index(l) for l in lines if l.startswith('Sniper Routine:')]
    ends = [lines.index(l) for l in lines if l.startswith('Sniper Routine Analized:')]
    for start, end in zip(starts, ends):
        sublines = lines[start:end]
        if len(sublines) == 0:
            log('Encountered empty sublines.', sublines, 'Skipping ...')
            continue
        func = sublines[0].strip().replace('Sniper Routine:', '')
        func = func[:func.find('StartAddr:')]
        func = func.strip()
        log('Function:', func)
        for subline in sublines:
            splits = subline.strip().split()
            if len(splits) == 0:
                log('Encountered empty splits.', splits, 'Skipping ...')
                continue
            if 'Block[' in splits[0]:
                # block started
                blk_start_addr = splits[-3]
                blk_end_addr = splits[-1]
                if(blk_start_addr != blk_end_addr):
                    curr_blk += 1
                    blocks[curr_blk] = {
                        'start': blk_start_addr,
                        'end': blk_end_addr,
                        'function': func,
                        'ips': []
                    }
                else:
                    log('Encountered empty block.', blk_start_addr, 'Skipping ...')
            elif 'instruction' in splits[0]:
                # ips within the block
                ip = splits[-1].split(':')[-1]
                blocks[curr_blk]['ips'].append(ip)

print(json.dumps(blocks, indent=4))

    